class Solution:
    def componentValue(self, nums, edges):
        # Brute force over every subset of edges to delete (feasible for small n).
        # A subset is valid if all resulting connected components have equal sum.
        # Maximize the number of deleted edges among valid subsets.
        n = len(nums)
        m = len(edges)
        best = 0
        for mask in range(1 << m):
            par = list(range(n))
            def find(x):
                while par[x] != x:
                    par[x] = par[par[x]]
                    x = par[x]
                return x
            cut = 0
            for i in range(m):
                if mask & (1 << i):
                    cut += 1
                else:
                    a, b = edges[i]
                    ra, rb = find(a), find(b)
                    if ra != rb:
                        par[ra] = rb
            comp_sum = {}
            for v in range(n):
                r = find(v)
                comp_sum[r] = comp_sum.get(r, 0) + nums[v]
            vals = list(comp_sum.values())
            if all(x == vals[0] for x in vals):
                if cut > best:
                    best = cut
        return best

