import sys
class Solution:
    def componentValue(self, nums, edges):
        sys.setrecursionlimit(100000)
        n = len(nums)
        total = sum(nums)
        mx = max(nums)
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        # topological order from root 0
        parent = [-1] * n
        order = []
        visited = [False] * n
        st = [0]
        visited[0] = True
        while st:
            u = st.pop()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    st.append(v)
        def feasible(target):
            sub = nums[:]
            for u in reversed(order):
                if sub[u] == target:
                    sub[u] = 0
                elif sub[u] > target:
                    return False
                if parent[u] != -1:
                    sub[parent[u]] += sub[u]
            return sub[0] == 0
        # candidate target = total / parts; bigger parts = smaller target = more cuts
        for parts in range(n, 0, -1):
            if total % parts != 0:
                continue
            target = total // parts
            if target < mx:
                continue
            if feasible(target):
                return parts - 1
        return 0

