var componentValue = function(nums, edges) {
    const n = nums.length;
    let total = 0, mx = 0;
    for (const v of nums) { total += v; if (v > mx) mx = v; }
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    const st = [0];
    visited[0] = true;
    while (st.length) {
        const u = st.pop();
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) { visited[v] = true; parent[v] = u; st.push(v); }
        }
    }
    const feasible = (target) => {
        const sub = nums.slice();
        for (let i = order.length - 1; i >= 0; i--) {
            const u = order[i];
            if (sub[u] === target) sub[u] = 0;
            else if (sub[u] > target) return false;
            if (parent[u] !== -1) sub[parent[u]] += sub[u];
        }
        return sub[0] === 0;
    };
    for (let parts = n; parts >= 1; parts--) {
        if (total % parts !== 0) continue;
        const target = total / parts;
        if (target < mx) continue;
        if (feasible(target)) return parts - 1;
    }
    return 0;
};
